mapper.select:
SELECT * FROM ( SELECT ROWNUM RN, A.* FROM (
SELECT VA.Volun_Act_No, VA.Volun_Act_Title, O.ORGAN_NAME AS orgName, VA.Volun_Act_Recru_Begin, VA.Volun_Act_Recru_End, VA.Volun_Act_Point, VA.Volun_Act_Address,
CASE VA.Volun_Act_Act_Type WHEN 1 THEN '환경' WHEN 2 THEN '의료' WHEN 3 THEN '교육' WHEN 4 THEN '생활·편의' WHEN 5 THEN '문화·체육·예술' ELSE '기타' END AS actTypeName,
CASE VA.Volun_Act_Age_Group WHEN 1 THEN '청소년' WHEN 2 THEN '청년' WHEN 3 THEN '직장인' END AS ageGroupName
FROM TBL_VOLUN_ACTIVITY VA LEFT JOIN TBL_ORGAN O ON VA.Volun_Act_Organ_No = O.ORGAN_NO
1 = 1
AND VA.Volun_Act_Act_Type = #{volunActActType}
AND VA.Volun_Act_Age_Group = #{volunActAgeGroup}
AND SYSDATE BETWEEN VA.Volun_Act_Recru_Begin AND VA.Volun_Act_Recru_End
AND SYSDATE < VA.Volun_Act_Recru_Begin
AND SYSDATE > VA.Volun_Act_Recru_End
AND O.ORGAN_NAME LIKE CONCAT('%', #{organization}, '%')
AND VA.Volun_Act_Title LIKE CONCAT('%', #{keyword}, '%')
AND VA.Volun_Act_Point = #{keyword}
ORDER BY VA.Volun_Act_No DESC
) A WHERE ROWNUM <= #{endRow}
) WHERE RN > #{startRow}
